const box=document.querySelector('#items');let seq=0;function add(data={}){const id=++seq,row=document.createElement('div');row.className='item';row.innerHTML=`<i></i><label>รหัสสินค้า<input class="code" value="${data.code||''}"></label><label>ชื่อสินค้า<input class="name" required value="${data.name||''}"></label><label>จำนวน<input class="quantity" required type="number" min="1" value="${data.quantity||1}"></label><label>หน่วย<input class="unit" value="${data.unit||'ชิ้น'}"></label><label>หมายเหตุ<input class="note" value="${data.note||''}"></label><button class="remove" type="button">×</button>`;row.querySelector('.remove').onclick=()=>{row.remove();calc()};row.addEventListener('input',calc);box.append(row);calc()}function calc(){[...box.children].forEach((r,i)=>r.querySelector('i').textContent=i+1);document.querySelector('#count').textContent=box.children.length+' รายการ';document.querySelector('#qty').textContent=[...box.children].reduce((s,r)=>s+(+r.querySelector('.quantity').value||0),0)+' หน่วย'}document.querySelector('#add').onclick=()=>add();
document.querySelector('#orderForm').onsubmit=e=>{e.preventDefault();const f=new FormData(e.target),number='PO-'+new Date().toISOString().slice(2,10).replaceAll('-','')+'-'+String(Date.now()).slice(-4),order={number,createdAt:new Date().toISOString(),customer:Object.fromEntries(f),items:[...box.children].map(r=>({code:r.querySelector('.code').value,name:r.querySelector('.name').value,quantity:+r.querySelector('.quantity').value,unit:r.querySelector('.unit').value,note:r.querySelector('.note').value}))};const payload=JSON.stringify(order);localStorage.setItem('pakarang-latest-order',payload);document.querySelector('#quotationLink').href='Pakarang-Order.html?customerOrder='+encodeURIComponent(payload);e.target.style.display='none';document.querySelector('#success').style.display='block';document.querySelector('#orderNo').textContent='เลขที่ '+number+' ฝ่ายขายสามารถเปิดข้อมูลนี้ในหน้าใบเสนอราคาได้ทันที'};
document.documentElement.style.setProperty('--b','#075c70');document.documentElement.style.setProperty('--m','#637982');document.documentElement.style.setProperty('--l','#cfe1e1');document.documentElement.style.setProperty('--s','#eff8f8');document.body.style.background='#edf6f5';document.querySelector('.top .brand').innerHTML='<img src="../assets/images/ac-foods-logo.png" alt="A AND C FOODS SHOP" style="width:145px;height:50px;object-fit:contain">';document.title='ใบสั่งซื้อสินค้า | A AND C FOODS SHOP';document.querySelector('[name="email"]')?.closest('label')?.remove();try{const customer=JSON.parse(localStorage.getItem('ac-current-customer'))||JSON.parse(localStorage.getItem('ac-customer-account'))||{};['company','contact','phone','taxId','address'].forEach(name=>{const field=document.querySelector(`[name="${name}"]`);if(field&&customer[name])field.value=customer[name]})}catch(error){console.warn('ไม่สามารถเติมข้อมูลลูกค้าอัตโนมัติได้',error)}

