(() => {
  const allCatalog=window.PRODUCT_CATALOG||[];
  const openCatalog=allCatalog.filter(item=>String(item.status||'').trim()==='เปิด E-catalog');
  const catalog=openCatalog.length?openCatalog:allCatalog;
  const catalogStatus=document.createElement('span');catalogStatus.textContent=`สินค้าในระบบ ${catalog.length.toLocaleString('th-TH')} รายการ`;catalogStatus.style.cssText='display:inline-block;margin-top:8px;padding:5px 10px;border-radius:16px;background:#dff3f0;color:#075c70;font-size:11px;font-weight:700';document.querySelector('.heading>div')?.append(catalogStatus);
  document.querySelector('[name="note"]')?.closest('.card')?.remove();
  box.innerHTML='';
  window.add=function(data={}){
    const row=document.createElement('div');row.className='item';
    row.innerHTML=`<i></i><label>รหัสสินค้า<input class="code" value="${data.code||''}" readonly></label><label class="product-wrap">ชื่อสินค้า<input class="name" required autocomplete="off" value="${data.name||''}" placeholder="พิมพ์ชื่อหรือรหัสสินค้า"><div class="product-menu-customer"></div></label><label>จำนวน<input class="quantity" required type="number" min="1" value="${data.quantity||''}"></label><label>หน่วย<input class="unit" value="${data.unit||''}" readonly></label><label>ราคา/หน่วย<input class="price-display" value="${data.price||''}" readonly></label><label>รวมเงิน<input class="line-total-display" value="0.00" readonly></label><button class="remove" type="button">×</button>`;
    const name=row.querySelector('.name'),menu=row.querySelector('.product-menu-customer');
    const choose=item=>{const customerPrice=Number(item.retailPrice??item.price??0);row.querySelector('.code').value=item.code;name.value=item.name;row.querySelector('.unit').value=item.unit||'ชิ้น';row.querySelector('.price-display').value=customerPrice.toLocaleString('th-TH',{minimumFractionDigits:2});row.dataset.price=customerPrice;menu.classList.remove('open');calc()};
    const show=()=>{const q=name.value.trim().toLowerCase();const found=(q?catalog.filter(item=>item.name.toLowerCase().includes(q)||item.code.toLowerCase().includes(q)):catalog).slice(0,10);menu.innerHTML=found.map((item,i)=>`<button type="button" class="product-choice" data-i="${i}"><b>${item.code}</b><span>${item.name}</span><strong>฿${Number(item.retailPrice??item.price??0).toLocaleString('th-TH',{minimumFractionDigits:2})}</strong></button>`).join('')||'<div style="padding:12px;color:#687d82;font-size:11px">ไม่พบสินค้า</div>';menu.classList.add('open');menu.querySelectorAll('.product-choice').forEach((button,i)=>button.onmousedown=e=>{e.preventDefault();choose(found[i])})};
    name.onfocus=show;name.oninput=show;name.onblur=()=>setTimeout(()=>menu.classList.remove('open'),150);row.querySelector('.remove').onclick=()=>{row.remove();calc()};row.addEventListener('input',calc);box.append(row);calc();
    if(data.code){const match=catalog.find(item=>item.code===data.code);if(match)choose(match)}
  };
  document.querySelector('#add').onclick=()=>window.add();
  document.querySelector('#printOrder').onclick=()=>window.print();
  const renderSavedItems=items=>{const area=document.querySelector('#savedOrderItems');area.innerHTML='';const head=document.createElement('div');head.className='saved-item saved-head';['ลำดับ','รหัสสินค้า','รายการสินค้า','จำนวน','หน่วย','ราคา/หน่วย','รวม'].forEach(text=>{const cell=document.createElement('span');cell.textContent=text;head.append(cell)});area.append(head);let totalQty=0,totalPrice=0;items.forEach((item,index)=>{const lineTotal=Number(item.quantity||0)*Number(item.price||0);totalQty+=Number(item.quantity||0);totalPrice+=lineTotal;const row=document.createElement('div');row.className='saved-item';[index+1,item.code,item.name,item.quantity,item.unit,item.price?Number(item.price).toLocaleString('th-TH',{minimumFractionDigits:2}):'-',item.price?lineTotal.toLocaleString('th-TH',{minimumFractionDigits:2}):'-'].forEach(text=>{const cell=document.createElement('span');cell.textContent=text;row.append(cell)});area.append(row)});document.querySelector('#poTotals').textContent=`รวม ${items.length} รายการ • จำนวน ${totalQty.toLocaleString('th-TH')} หน่วย • มูลค่ารวม ${totalPrice.toLocaleString('th-TH',{minimumFractionDigits:2})} บาท`};
  document.querySelector('#orderForm').onsubmit=e=>{e.preventDefault();const f=new FormData(e.target),number='PO-'+new Date().toISOString().slice(2,10).replaceAll('-','')+'-'+String(Date.now()).slice(-4),order={number,createdAt:new Date().toISOString(),status:'pending',quoteNumber:'',quotedAt:'',customer:Object.fromEntries(f),items:[...box.children].map(r=>({code:r.querySelector('.code').value,name:r.querySelector('.name').value,quantity:+r.querySelector('.quantity').value,unit:r.querySelector('.unit').value,price:+r.dataset.price||0}))};const payload=JSON.stringify(order);localStorage.setItem('pakarang-latest-order',payload);let history=[];try{history=JSON.parse(localStorage.getItem('ac-customer-orders'))||[]}catch{}history.unshift(order);localStorage.setItem('ac-customer-orders',JSON.stringify(history));renderSavedItems(order.items);const c=order.customer,put=(id,value)=>document.querySelector(id).textContent=value||'-';put('#poPrintNumber',number);put('#poPrintDate',new Date(order.createdAt).toLocaleDateString('th-TH'));put('#poCompany',c.company);put('#poContact',c.contact);put('#poPhone',c.phone);put('#poDelivery',c.deliveryDate?new Date(c.deliveryDate+'T00:00:00').toLocaleDateString('th-TH'):'-');put('#poAddress',c.address);e.target.style.display='none';document.querySelector('#success').style.display='block';document.querySelector('#orderNo').textContent='เลขที่ '+number+' • รายการที่บันทึกไว้สำหรับฝ่ายขาย';document.querySelector('#backToOrder').onclick=()=>{document.querySelector('#success').style.display='none';e.target.style.display='grid';box.innerHTML='';calc();window.scrollTo({top:0,behavior:'smooth'})}};
})();

document.querySelector('.top .brand').innerHTML='<img src="../assets/images/ac-foods-shop-logo.jpg" alt="A AND C FOODS SHOP" style="width:58px;height:58px;border-radius:50%;object-fit:contain;background:white">';box.innerHTML='';calc();

function calc(){
  const rows=[...box.children];
  rows.forEach((row,index)=>row.querySelector('i').textContent=index+1);
  const totalQuantity=rows.reduce((sum,row)=>sum+(Number(row.querySelector('.quantity')?.value)||0),0);
  const totalPrice=rows.reduce((sum,row)=>sum+(Number(row.querySelector('.quantity')?.value)||0)*(Number(row.dataset.price)||0),0);
  rows.forEach(row=>{const lineTotal=(Number(row.querySelector('.quantity')?.value)||0)*(Number(row.dataset.price)||0),display=row.querySelector('.line-total-display');if(display)display.value=lineTotal.toLocaleString('th-TH',{minimumFractionDigits:2,maximumFractionDigits:2})});
  document.querySelector('#count').textContent=`${rows.length} รายการ`;
  document.querySelector('#qty').textContent=`${totalQuantity.toLocaleString('th-TH')} หน่วย`;
  const priceTotal=document.querySelector('#priceTotal');
  if(priceTotal)priceTotal.textContent=`รวมราคา ${totalPrice.toLocaleString('th-TH',{minimumFractionDigits:2,maximumFractionDigits:2})} บาท`;
}

(()=>{
  const summary=document.querySelector('.sum');
  if(summary&&!document.querySelector('#priceTotal')){const total=document.createElement('b');total.id='priceTotal';total.className='price-total';summary.append(total)}
  const form=document.querySelector('#orderForm');
  form?.addEventListener('keydown',event=>{if(event.key==='Enter'&&event.target.tagName!=='TEXTAREA'){event.preventDefault();event.stopPropagation()}});
  const validateOrderItems=()=>{const rows=[...box.children];if(!rows.length){alert('กรุณาเพิ่มสินค้าอย่างน้อย 1 รายการก่อนบันทึกใบสั่งซื้อ');return false}const invalid=rows.some(row=>!row.querySelector('.code')?.value.trim()||!row.querySelector('.name')?.value.trim()||!(Number(row.querySelector('.quantity')?.value)>0));if(invalid){alert('กรุณาเลือกสินค้าและกรอกจำนวนให้ครบทุกรายการก่อนบันทึก');return false}return true};
  form?.addEventListener('submit',event=>{if(!validateOrderItems()){event.preventDefault();event.stopImmediatePropagation()}},true);
  const saveButton=form?.querySelector('.submit .primary');
  if(saveButton){saveButton.type='button';saveButton.addEventListener('click',()=>{if(form.reportValidity()&&validateOrderItems())form.requestSubmit()})}
  calc();
})();

/* Print one purchase order from the customer's personal order history. */
(()=>{
  const read=(key,fallback=[])=>{try{return JSON.parse(localStorage.getItem(key))||fallback}catch{return fallback}};
  const esc=value=>String(value??'').replace(/[&<>"']/g,char=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[char]));
  const money=value=>Number(value||0).toLocaleString('th-TH',{minimumFractionDigits:2,maximumFractionDigits:2});
  const currentCustomer=()=>read('ac-current-customer',read('ac-customer-account',{}));
  const isMine=order=>{const account=currentCustomer(),customer=order.customer||{},phone=value=>String(value||'').replace(/\D/g,''),accountPhone=phone(account.phone);if(accountPhone)return phone(customer.phone)===accountPhone;const names=[account.company,account.contact,account.username].filter(Boolean).map(value=>String(value).trim().toLowerCase());return [customer.company,customer.contact,customer.username].some(value=>names.includes(String(value||'').trim().toLowerCase()))};
  const findOrder=number=>read('ac-customer-orders').find(order=>order.number===number&&isMine(order));
  const itemRows=(items,originalItems)=>items.map((item,index)=>{const original=originalItems.find(source=>source.code===item.code)||{},orderedQuantity=Number(item.orderedQuantity??original.quantity??item.quantity??0),quotedQuantity=Number(item.quotedQuantity??item.quantity??0),orderedUnit=item.orderedUnit||original.unit||item.unit||'',quotedUnit=item.quotedUnit||item.unit||orderedUnit,price=Number(item.price||0),total=Number(item.total??quotedQuantity*price);return `<tr><td>${index+1}</td><td><b>${esc(item.code||'-')}</b></td><td>${esc(item.name||'-')}</td><td>${esc(orderedQuantity)}</td><td>${esc(orderedUnit)}</td><td>${esc(quotedQuantity)}</td><td>${esc(quotedUnit)}</td><td>฿${money(price)}</td><td><b>฿${money(total)}</b></td><td>${esc(item.note||'')}</td></tr>`}).join('');
  const section=(title,items,originalItems,out=false)=>{if(!items.length)return '';const total=items.reduce((sum,item)=>sum+Number(item.total??(Number(item.quotedQuantity??item.quantity??0)*Number(item.price||0))),0);return `<section class="history-pdf-section ${out?'out-stock':''}"><h2>${title}</h2><table><thead><tr><th>ลำดับที่</th><th>รหัส</th><th>รายการสินค้า</th><th>จำนวนสั่งซื้อ</th><th>หน่วยสั่งซื้อ</th><th>จำนวนตอบกลับ</th><th>หน่วยตอบกลับ</th><th>ราคาตอบกลับ</th><th>รวม</th><th>หมายเหตุ</th></tr></thead><tbody>${itemRows(items,originalItems)}</tbody></table><h3>${out?'รวมสินค้าที่ไม่มีในสต็อก':'รวมรายการสินค้า'} ฿${money(total)}</h3></section>`};
  const printOrder=order=>{
    const quotation=order.quotation||{},items=quotation.items||order.originalItems||order.items||[],originalItems=order.originalItems||order.items||[];
    const normal=items.filter(item=>item.section!=='out-of-stock'),out=items.filter(item=>item.section==='out-of-stock'),customer=order.customer||{};
    const grandTotal=quotation.grandTotal??items.reduce((sum,item)=>sum+Number(item.total??(Number(item.quotedQuantity??item.quantity??0)*Number(item.price||0))),0);
    const address=customer.address||[customer.addressHouse,customer.subdistrict,customer.district,customer.province,customer.postalCode].filter(Boolean).join(' ');
    const orderNotes=[quotation.orderNote,order.orderNote,order.note,customer.note,quotation.note].filter(Boolean).filter((note,index,all)=>all.indexOf(note)===index);
    const deliveryValue=quotation.arrivalDate||customer.deliveryDate||'',deliveryDate=deliveryValue?new Date(deliveryValue+'T00:00:00').toLocaleDateString('th-TH'):'-',arrivalTime=quotation.arrivalTime||'-';
    document.querySelector('#historyOrderPdf')?.remove();document.querySelector('#historyPdfPageStyle')?.remove();
    const printable=document.createElement('article');printable.id='historyOrderPdf';printable.className='history-pdf';
    printable.innerHTML=`<header><div class="history-pdf-company"><img src="../assets/images/ac-foods-shop-logo.jpg" alt="A AND C FOODS SHOP"><div><h1>A AND C FOODS SHOP</h1><p>ที่อยู่: เลขที่ 356/1 ซอย 8 ถนนมิตรภาพ ตำบลในเมือง อำเภอเมืองนครราชสีมา จังหวัดนครราชสีมา 30000</p><p>โทร: 091-760-6423</p></div></div><div><h1>ใบสั่งซื้อ</h1><p>เลขที่: <b>${esc(order.number||'-')}</b></p><p>วันที่: ${order.createdAt?new Date(order.createdAt).toLocaleDateString('th-TH'):'-'}</p></div></header><div class="history-pdf-customer"><p><b>ลูกค้า:</b> ${esc(customer.company||'-')}</p><p><b>เบอร์โทรศัพท์:</b> ${esc(customer.phone||'-')}</p><p><b>ที่อยู่จัดส่ง:</b> ${esc(address||'-')}</p><p><b>วันที่ส่งถึง:</b> ${esc(deliveryDate)} &nbsp;&nbsp; <b>เวลาประมาณ:</b> ${esc(arrivalTime)}</p></div>${section('รายละเอียดออเดอร์',normal,originalItems)}${section('สินค้าที่ไม่มีในสต็อก',out,originalItems,true)}<div class="history-pdf-note">${orderNotes.length?`<b>หมายเหตุสำหรับออเดอร์:</b>${orderNotes.map(note=>`<p>• ${esc(note)}</p>`).join('')}<hr>`:''}<p>• ราคานี้ยังไม่รวม VAT 7%</p><p>• กรุณายืนยันราคาและสินค้าอีกครั้งก่อนสั่งซื้อ</p></div><div class="history-pdf-total">มูลค่ารวม ${money(grandTotal)} บาท</div>`;
    const pageStyle=document.createElement('style');pageStyle.id='historyPdfPageStyle';pageStyle.textContent='@page{size:A4;margin:0}';document.head.append(pageStyle);document.body.append(printable);document.body.classList.add('print-history-order');
    const cleanup=()=>{document.body.classList.remove('print-history-order');printable.remove();pageStyle.remove()};window.addEventListener('afterprint',cleanup,{once:true});window.print();setTimeout(()=>{if(document.body.classList.contains('print-history-order'))cleanup()},1500)
  };
  const addButtons=()=>document.querySelectorAll('.history-order').forEach(article=>{if(article.querySelector('.history-pdf-button'))return;const number=article.querySelector('.history-summary b')?.textContent.trim();if(!number)return;const button=document.createElement('button');button.type='button';button.className='history-pdf-button';button.textContent='ดู / บันทึก PDF';button.dataset.orderNumber=number;article.querySelector('.history-summary')?.append(button)});
  document.addEventListener('click',event=>{if(event.target.closest('#orderHistoryButton'))setTimeout(addButtons);const button=event.target.closest('.history-pdf-button');if(!button)return;const order=findOrder(button.dataset.orderNumber);if(!order){alert('ไม่พบใบสั่งซื้อรายการนี้');return}printOrder(order)});
})();

(()=>{
  const heading=document.querySelector('.heading');if(!heading||document.querySelector('#orderHistoryButton'))return;
  const button=document.createElement('button');button.type='button';button.id='orderHistoryButton';button.className='history-button';button.textContent='ประวัติใบสั่งซื้อของฉัน';heading.append(button);
  const panel=document.createElement('section');panel.id='customerOrderHistory';panel.className='customer-history';panel.hidden=true;panel.innerHTML='<div class="history-head"><div><small>MY PURCHASE ORDERS</small><h2>ประวัติใบสั่งซื้อของฉัน</h2></div><button type="button" id="closeOrderHistory">× ปิด</button></div><div id="customerHistoryList"></div>';document.querySelector('.form').before(panel);
  const safe=value=>String(value??'').replace(/[&<>"']/g,char=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[char]));
  const renderHistory=()=>{let orders=[];try{orders=JSON.parse(localStorage.getItem('ac-customer-orders'))||[]}catch{}let customer={};try{customer=JSON.parse(localStorage.getItem('ac-current-customer'))||JSON.parse(localStorage.getItem('ac-customer-account'))||{}}catch{}const phone=String(customer.phone||'').replace(/\D/g,''),names=[customer.company,customer.contact,customer.username].filter(Boolean).map(value=>String(value).trim().toLowerCase()),mine=orders.filter(order=>{const c=order.customer||{},orderPhone=String(c.phone||'').replace(/\D/g,''),orderNames=[c.company,c.contact,c.username].filter(Boolean).map(value=>String(value).trim().toLowerCase());return phone?orderPhone===phone:names.some(name=>orderNames.includes(name))}),list=document.querySelector('#customerHistoryList');if(!mine.length){list.innerHTML='<div class="history-empty">ยังไม่มีประวัติใบสั่งซื้อ</div>';return}list.innerHTML=mine.map(order=>{const quoted=order.status==='completed'&&order.quotation,items=quoted?.items||order.originalItems||order.items||[],total=quoted?.grandTotal??items.reduce((sum,item)=>sum+(Number(item.quantity)||0)*(Number(item.price)||0),0),status=order.status==='cancelled'?'ยกเลิกแล้ว':quoted?'ทำใบเสนอราคาแล้ว':'รอฝ่ายขายทำใบเสนอราคา';return `<article class="history-order"><div class="history-summary"><div><b>${safe(order.number||'-')}</b><small>${order.createdAt?new Date(order.createdAt).toLocaleString('th-TH'):'-'}</small>${quoted?`<small class="quote-number">ใบเสนอราคา: ${safe(quoted.documentNumber||order.quoteNumber||'-')}</small>`:''}</div><span class="history-status ${safe(order.status||'pending')}">${status}</span><strong>${total.toLocaleString('th-TH',{minimumFractionDigits:2})} บาท</strong></div><div class="history-items">${items.map((item,index)=>`<div class="${item.section==='out-of-stock'?'history-out-stock':''}"><span>${index+1}</span><b>${safe(item.code||'-')}</b><span>${safe(item.name||'-')}${item.section==='out-of-stock'?'<small>สินค้าไม่มีในสต๊อก</small>':''}</span><span>${safe(item.quantity||0)} ${safe(item.unit||'')}</span><span>${Number(item.price||0).toLocaleString('th-TH',{minimumFractionDigits:2})}</span><strong>${Number(item.total??((Number(item.quantity)||0)*(Number(item.price)||0))).toLocaleString('th-TH',{minimumFractionDigits:2})}</strong></div>`).join('')}</div></article>`}).join('')};
  button.onclick=()=>{renderHistory();panel.hidden=false;document.querySelector('.form').hidden=true;panel.scrollIntoView({behavior:'smooth',block:'start'})};document.querySelector('#closeOrderHistory').onclick=()=>{panel.hidden=true;document.querySelector('.form').hidden=false};
})();
